import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  nav: { background: '#1a3a5c', color: '#fff', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 60, boxShadow: '0 2px 8px rgba(0,0,0,0.2)' },
  brand: { fontSize: 18, fontWeight: 700, color: '#fff', textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 10 },
  links: { display: 'flex', alignItems: 'center', gap: 8 },
  link: { color: '#cce4ff', textDecoration: 'none', padding: '6px 14px', borderRadius: 6, fontSize: 14, transition: 'background 0.2s' },
  logoutBtn: { background: '#e74c3c', color: '#fff', border: 'none', padding: '6px 16px', borderRadius: 6, cursor: 'pointer', fontSize: 14, fontWeight: 600 },
  userBadge: { background: '#2980b9', padding: '4px 12px', borderRadius: 20, fontSize: 13, marginRight: 8 }
};

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <nav style={s.nav}>
      <Link to="/dashboard" style={s.brand}>🚌 Bus Pass System</Link>
      <div style={s.links}>
        {user?.role === 'student' && (
          <>
            <Link to="/dashboard" style={s.link}>Dashboard</Link>
            <Link to="/apply" style={s.link}>Apply Pass</Link>
            <Link to="/my-passes" style={s.link}>My Passes</Link>
          </>
        )}
        {user?.role === 'admin' && (
          <>
            <Link to="/dashboard" style={s.link}>Dashboard</Link>
            <Link to="/admin/passes" style={s.link}>Manage Passes</Link>
            <Link to="/admin/reports" style={s.link}>Reports</Link>
          </>
        )}
        <span style={s.userBadge}>{user?.name} ({user?.role})</span>
        <button style={s.logoutBtn} onClick={handleLogout}>Logout</button>
      </div>
    </nav>
  );
}
